import json

# Create invoices
items_techstart = [
    {"description": "Software Development", "quantity": 80, "price": 150},
    {"description": "Code Review", "quantity": 10, "price": 100},
]
inv_techstart = json.loads(tools.create_invoice(client_name="TechStart Inc", items=items_techstart, due_days=30))

items_design = [
    {"description": "UI/UX Design", "quantity": 40, "price": 125},
    {"description": "Prototyping", "quantity": 15, "price": 100},
]
inv_design = json.loads(tools.create_invoice(client_name="Design Studio", items=items_design, due_days=15))

# Update TechStart invoice status to 'sent'
techstart_id = inv_techstart.get("invoice_id")
if not techstart_id:
    techstart_id = inv_techstart.get("id")
if not techstart_id:
    techstart_id = inv_techstart.get("invoice", {}).get("invoice_id") or inv_techstart.get("invoice", {}).get("id")

inv_techstart_updated = json.loads(tools.update_invoice_status(invoice_id=techstart_id, new_status="sent"))

# Fetch invoices and state summary
all_invoices = json.loads(tools.get_invoices())
state_summary = json.loads(tools.get_state_summary())

def safe_number(v):
    if v is None:
        return 0
    if isinstance(v, (int, float)):
        return v
    try:
        return float(v)
    except Exception:
        return 0

def invoice_total(inv):
    if inv is None:
        return 0
    if inv.get("total") is not None:
        return safe_number(inv.get("total"))
    total = 0
    for it in inv.get("items", []) or []:
        qty = safe_number(it.get("quantity"))
        price = safe_number(it.get("price"))
        total += qty * price
    return total

def invoice_paid(inv):
    for k in ["amount_paid", "paid_amount", "payments_total"]:
        if inv.get(k) is not None:
            return safe_number(inv.get(k))
    return 0

invoice_summaries = []
outstanding_total = 0

for inv in all_invoices or []:
    status = inv.get("status", "unknown")
    total = invoice_total(inv)
    paid = invoice_paid(inv)
    inv_id = inv.get("invoice_id") or inv.get("id")
    if not inv_id and isinstance(inv.get("invoice"), dict):
        inv_id = inv["invoice"].get("invoice_id") or inv["invoice"].get("id")
    client_name = inv.get("client_name") or inv.get("client") or inv.get("customer_name")
    if not client_name and isinstance(inv.get("invoice"), dict):
        client_name = inv["invoice"].get("client_name") or inv["invoice"].get("client") or inv["invoice"].get("customer_name")

    outstanding = 0
    if str(status).lower() not in ["paid", "void", "voided", "cancelled", "canceled"]:
        outstanding = total - paid
        if outstanding < 0:
            outstanding = 0
        outstanding_total += outstanding

    invoice_summaries.append({
        "invoice_id": inv_id,
        "client_name": client_name,
        "status": status,
        "issue_date": inv.get("issue_date"),
        "due_date": inv.get("due_date"),
        "total": total,
        "amount_paid": paid,
        "outstanding": outstanding
    })

result = {
    "created_invoices": {
        "techstart": inv_techstart,
        "design_studio": inv_design
    },
    "techstart_status_update": inv_techstart_updated,
    "all_invoices_summary": invoice_summaries,
    "total_outstanding_receivables": outstanding_total,
    "state_summary": state_summary
}

