import json

# Robustly obtain a working tool handle without using globals().
# Some runtimes inject `tools`, others inject `tool`, and some expose callables at top-level.
tool_handle = None

try:
    if tools is not None:
        tool_handle = tools
except NameError:
    tool_handle = None

if tool_handle is None:
    try:
        if tool is not None:
            tool_handle = tool
    except NameError:
        tool_handle = None

# If we still don't have a handle, raise a structured result.
if tool_handle is None:
    result = {"error": "No tool handle found (expected `tools` or `tool`)."}
else:
    # Prefer direct methods if callable; otherwise use .call
    def can_call_direct(name):
        try:
            fn = tool_handle.__dict__.get(name)
            return fn is not None and callable(fn)
        except Exception:
            return False

    def call_tool(path, args):
        return json.loads(tool_handle.call(path, args))

    def create_tx(transaction_type, category, amount, description, account):
        if can_call_direct("create_transaction"):
            return json.loads(tool_handle.create_transaction(
                transaction_type=transaction_type,
                category=category,
                amount=amount,
                description=description,
                account=account
            ))
        return call_tool("/accounting/create_transaction", {
            "transaction_type": transaction_type,
            "category": category,
            "amount": amount,
            "description": description,
            "account": account
        })

    def get_fin_summary():
        if can_call_direct("get_financial_summary"):
            return json.loads(tool_handle.get_financial_summary())
        return call_tool("/accounting/get_financial_summary", {})

    def get_txns(account, transaction_type):
        if can_call_direct("get_transactions"):
            return json.loads(tool_handle.get_transactions(account=account, transaction_type=transaction_type))
        return call_tool("/accounting/get_transactions", {"account": account, "transaction_type": transaction_type})

    def get_balance(account):
        if can_call_direct("get_account_balance"):
            return json.loads(tool_handle.get_account_balance(account))
        return call_tool("/accounting/get_account_balance", {"account": account})

    def get_state():
        if can_call_direct("get_state_summary"):
            return json.loads(tool_handle.get_state_summary())
        return call_tool("/accounting/get_state_summary", {})

    transactions_to_create = [
        ("expense", "Office - Rent", 2500, "Monthly office rent"),
        ("expense", "Office - Utilities", 180, "Monthly utilities"),
        ("expense", "Office - Internet", 100, "Monthly internet service"),
        ("expense", "Office - Office supplies", 250, "Office supplies purchase"),
        ("expense", "Office - Cleaning service", 200, "Monthly cleaning service"),
        ("expense", "Marketing - Social media ads", 600, "Social media advertising spend"),
        ("expense", "Marketing - Content creation", 800, "Content creation services"),
        ("expense", "Marketing - SEO tools", 150, "SEO tools subscription"),
        ("expense", "Operations - Software licenses", 450, "Software licenses"),
        ("expense", "Operations - Cloud hosting", 300, "Cloud hosting charges"),
        ("expense", "Operations - Domain renewals", 50, "Domain renewal fees"),
        ("expense", "Professional Development - Online courses", 200, "Online course fees"),
        ("expense", "Professional Development - Conference ticket", 500, "Conference ticket purchase"),
        ("expense", "Professional Development - Books", 75, "Professional development books"),
    ]

    created = []
    for ttype, category, amount, desc in transactions_to_create:
        created.append(create_tx(ttype, category, amount, desc, "checking"))

    summary = get_fin_summary()
    all_tx = get_txns("checking", "expense")

    category_totals = {
        "Office": 0,
        "Marketing": 0,
        "Operations": 0,
        "Professional Development": 0
    }

    individual_expenses = []
    for tx in all_tx:
        cat = tx.get("category", "")
        amt = tx.get("amount", 0) or 0
        major = cat.split(" - ")[0] if " - " in cat else cat
        if major in category_totals:
            category_totals[major] = category_totals[major] + amt
        individual_expenses.append({
            "category": cat,
            "amount": amt,
            "description": tx.get("description", ""),
            "date": tx.get("date", "")
        })

    top3 = sorted(individual_expenses, key=lambda x: x["amount"], reverse=True)[:3]

    our_categories = set([x[1] for x in transactions_to_create])
    total_month_expenses = 0
    for tx in all_tx:
        if tx.get("category") in our_categories:
            total_month_expenses = total_month_expenses + (tx.get("amount", 0) or 0)

    checking_balance = get_balance("checking")
    state_summary = get_state()

    result = {
        "recorded_transactions_count": len(created),
        "category_totals": category_totals,
        "top_3_individual_expenses": top3,
        "total_expenses_for_month": total_month_expenses,
        "remaining_checking_account_balance": checking_balance,
        "financial_summary": summary,
        "state_summary": state_summary
    }

